class Solution {
    public int minMovesToMakePalindrome(String s) {
        char[] chars = s.toCharArray();
        int n = chars.length;
        int moves = 0;
        int left = 0;
        int right = n - 1;

        while (left < right) {
            if (chars[left] != chars[right]) {
                int mid = right;
                while (mid > left && chars[left] != chars[mid]) {
                    mid--;
                }
                if (mid == left) {
                    // Swap with the one before mid
                    for (int i = mid; i < right; i++) {
                        char temp = chars[i];
                        chars[i] = chars[i + 1];
                        chars[i + 1] = temp;
                        moves++;
                    }
                } else {
                    // Swap with the one at mid
                    for (int i = mid; i < right; i++) {
                        char temp = chars[i];
                        chars[i] = chars[i + 1];
                        chars[i + 1] = temp;
                        moves++;
                    }
                }
            }
            left++;
            right--;
        }
        return moves;
    }
}
